#!/usr/bin/env node
/**
 * Promote overview.md(x) into index.md(x) so the section landing page lives
 * at the directory's URL (e.g. /docs/storage/ instead of /docs/storage/overview).
 *
 * For each directory under src/content/docs/docs/:
 *   - if both `index.{md,mdx}` (auto-generated from `_category_.json
 *     generated-index` during the migration) and `overview.{md,mdx}` exist,
 *     delete the auto-generated index and rename overview -> index;
 *   - if only `overview.{md,mdx}` exists, rename it to `index`;
 *   - if only `index` exists, leave it.
 *
 * Then rewrite every markdown link of the form `/docs/.../overview` (with or
 * without trailing slash, with or without anchor) into `/docs/.../`.
 */
import { promises as fs } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const DOCS = path.join(ROOT, "src/content/docs/docs");

let promoted = 0;
let deletedAutoIndex = 0;
let renamedToIndex = 0;
let untouched = 0;

async function exists(p) {
  try {
    await fs.access(p);
    return true;
  } catch {
    return false;
  }
}

async function readFirstLines(p, n = 10) {
  const text = await fs.readFile(p, "utf8");
  return text.split(/\r?\n/).slice(0, n).join("\n");
}

async function isAutoGeneratedIndex(p) {
  // The migration script wrote landing pages whose body imports CardGrid/LinkCard
  // from @astrojs/starlight/components. Treat those as auto-generated and safe
  // to delete when a hand-written overview.md exists alongside.
  const head = await readFirstLines(p, 20);
  return head.includes("@astrojs/starlight/components");
}

async function processDir(dir) {
  for (const ent of await fs.readdir(dir, { withFileTypes: true })) {
    if (!ent.isDirectory()) continue;
    if (ent.name.startsWith(".") || ent.name.startsWith("_")) continue;
    await processDir(path.join(dir, ent.name));
  }

  let overview = null;
  let index = null;
  for (const candidate of ["overview.md", "overview.mdx"]) {
    const p = path.join(dir, candidate);
    if (await exists(p)) {
      overview = p;
      break;
    }
  }
  for (const candidate of ["index.md", "index.mdx"]) {
    const p = path.join(dir, candidate);
    if (await exists(p)) {
      index = p;
      break;
    }
  }

  if (overview && index) {
    if (await isAutoGeneratedIndex(index)) {
      await fs.unlink(index);
      deletedAutoIndex++;
      // promote the overview as the new index
      const target = path.join(
        dir,
        overview.endsWith(".mdx") ? "index.mdx" : "index.md",
      );
      await fs.rename(overview, target);
      renamedToIndex++;
      promoted++;
    } else {
      // Hand-written index alongside hand-written overview: leave both alone
      // so we don't risk losing content.
      untouched++;
    }
  } else if (overview && !index) {
    const target = path.join(
      dir,
      overview.endsWith(".mdx") ? "index.mdx" : "index.md",
    );
    await fs.rename(overview, target);
    renamedToIndex++;
    promoted++;
  }
}

async function rewriteLinks() {
  let edited = 0;
  let total = 0;
  async function walk(dir) {
    for (const ent of await fs.readdir(dir, { withFileTypes: true })) {
      const full = path.join(dir, ent.name);
      if (ent.isDirectory()) {
        await walk(full);
      } else if (/\.mdx?$/.test(ent.name)) {
        const original = await fs.readFile(full, "utf8");
        // Replace ](/docs/.../overview) and ](/docs/.../overview#anchor)
        // and ](/docs/.../overview/) with ](/docs/.../) preserving anchor.
        const next = original.replace(
          /\]\((\/docs\/[^)\s#]+?)\/overview(\/)?(#[^)\s]*)?\)/g,
          (_m, base, _slash, anchor) => `](${base}/${anchor || ""})`,
        );
        if (next !== original) {
          edited++;
          total += (original.match(
            /\]\((\/docs\/[^)\s#]+?)\/overview(\/)?(#[^)\s]*)?\)/g,
          ) || []).length;
          await fs.writeFile(full, next);
        }
      }
    }
  }
  await walk(path.join(ROOT, "src/content/docs"));
  return { edited, total };
}

await processDir(DOCS);
const linkStats = await rewriteLinks();

console.log(`promoted overview -> index: ${promoted}`);
console.log(`  auto-index files deleted: ${deletedAutoIndex}`);
console.log(`  overview files renamed:   ${renamedToIndex}`);
console.log(`untouched (both hand-written): ${untouched}`);
console.log(`link rewrites:                ${linkStats.total} in ${linkStats.edited} files`);
